from typing import List, Dict, Any, Optional, Callable
from leann.api import SearchResult
from leann.metadata_filter import MetadataFilterEngine
from collections import defaultdict


def apply_dynamic_filters(
    search_results: List[SearchResult],
    filter_specs: Dict[str, Dict[str, Any]],
    filter_logic: str = "AND"
) -> List[SearchResult]:
    """Apply dynamic metadata filters to search results with configurable logic.

    Args:
        search_results: List of SearchResult objects to filter
        filter_specs: Dictionary of filter specifications.
            Format: {"field_name": {"operator": value}}
            Example: {"category": {"==": "tech"}, "rating": {">=": 4.0}}
        filter_logic: "AND" (all filters must match) or "OR" (any filter matches)

    Returns:
        Filtered list of SearchResult objects
    """
    if not filter_specs:
        return search_results

    # Convert SearchResult objects to dictionaries for filtering
    result_dicts = []
    for result in search_results:
        result_dicts.append({
            "id": result.id,
            "score": result.score,
            "text": result.text,
            "metadata": result.metadata,
        })

    # Create filter engine instance
    filter_engine = MetadataFilterEngine()

    if filter_logic.upper() == "AND":
        # Apply all filters with AND logic (default behavior of MetadataFilterEngine)
        filtered_dicts = filter_engine.apply_filters(result_dicts, filter_specs)
    elif filter_logic.upper() == "OR":
        # Apply filters with OR logic: result must match at least one filter
        filtered_dicts = []
        for result_dict in result_dicts:
            # Check if result matches any of the filters
            matches_any = False
            for field_name, filter_spec in filter_specs.items():
                # Create single-field filter specification
                single_filter = {field_name: filter_spec}
                if filter_engine._evaluate_filters(result_dict, single_filter):
                    matches_any = True
                    break

            if matches_any:
                filtered_dicts.append(result_dict)
    else:
        raise ValueError(f"Unsupported filter logic: {filter_logic}. Use 'AND' or 'OR'.")

    # Convert filtered dictionaries back to SearchResult objects
    filtered_results = []
    for result_dict in filtered_dicts:
        # Find the original SearchResult object to preserve all attributes
        original_result = next(
            (result for result in search_results if result.id == result_dict["id"]),
            None
        )
        if original_result:
            filtered_results.append(original_result)

    return filtered_results

