from typing import List, Dict, Any, Optional
from leann.cli import LeannCLI
from leann.api import LeannBuilder, LeannSearcher
from pathlib import Path

def convert_cli_args_to_api_config(
    args_list: List[str],
    command_type: str = "build"
) -> Dict[str, Any]:
    """Convert CLI arguments to API configuration dictionary.

    Args:
        args_list: List of command line arguments
        command_type: Type of command ('build' or 'search')

    Returns:
        Dictionary containing API configuration extracted from CLI arguments
    """
    # Create CLI instance and parser
    cli = LeannCLI()
    parser = cli.create_parser()

    # Parse the arguments
    args = parser.parse_args(args_list)

    # Base configuration common to both commands
    config = {
        "index_path": getattr(args, 'index_path', None),
        "backend": getattr(args, 'backend', 'faiss'),
        "llm_config": _extract_llm_config(args),
        "embedding_model": getattr(args, 'embedding_model', None),
        "verbose": getattr(args, 'verbose', False),
        "port": getattr(args, 'port', None),
    }

    # Add command-specific parameters
    if command_type == "build":
        config.update({
            "docs_paths": _extract_docs_paths(args),
            "chunk_size": getattr(args, 'chunk_size', 1000),
            "chunk_overlap": getattr(args, 'chunk_overlap', 200),
        })
    elif command_type == "search":
        config.update({
            "query": getattr(args, 'query', None),
            "metadata_filters": _extract_metadata_filters(args),
            "top_k": getattr(args, 'top_k', 10),
        })
    else:
        raise ValueError(f"Unsupported command type: {command_type}")

    # Remove None values
    config = {k: v for k, v in config.items() if v is not None}

    return config

def _extract_llm_config(args) -> Optional[Dict[str, Any]]:
    """Extract LLM configuration from parsed arguments."""
    llm_config = {}

    # Extract LLM type and model
    llm_type = getattr(args, 'llm_type', None)
    llm_model = getattr(args, 'llm_model', None)

    if llm_type:
        llm_config["type"] = llm_type
    if llm_model:
        llm_config["model"] = llm_model

    # Extract API key if provided
    api_key = getattr(args, 'api_key', None)
    if api_key:
        llm_config["api_key"] = api_key

    # Extract host for Ollama
    if llm_type == "ollama":
        host = getattr(args, 'host', None)
        if host:
            llm_config["host"] = host

    return llm_config if llm_config else None

def _extract_docs_paths(args) -> List[Path]:
    """Extract document paths from parsed arguments."""
    docs_paths = getattr(args, 'docs_paths', [])
    if not docs_paths:
        return []

    # Convert to Path objects and ensure they exist
    paths = []
    for path_str in docs_paths:
        path = Path(path_str)
        if path.exists():
            paths.append(path)
        else:
            raise ValueError(f"Document path does not exist: {path}")

    return paths

def _extract_metadata_filters(args) -> Optional[Dict[str, Any]]:
    """Extract metadata filters from parsed arguments."""
    filters_str = getattr(args, 'metadata_filters', None)
    if not filters_str:
        return None

    try:
        # Parse metadata filters (assuming JSON format or key=value pairs)
        import json
        return json.loads(filters_str)
    except (json.JSONDecodeError, ImportError):
        # Fallback to simple key=value parsing
        filters = {}
        for filter_str in filters_str.split(','):
            if '=' in filter_str:
                key, value = filter_str.split('=', 1)
                filters[key.strip()] = value.strip()
        return filters if filters else None

